mapper.select:
SELECT a.id, a.project_id AS "projectId", a.company_id AS "companyId", a.applicant_id AS "applicantId", a.amount, a.reason, a.attachments, a.status, a.submit_time AS "submitTime", a.created_by AS "createdBy", a.created_at AS "createdAt", a.updated_by AS "updatedBy", a.updated_at AS "updatedAt", p.code AS "projectCode", p.name AS "projectName", applicant.name AS "applicantName", creator.name AS "createdByName" FROM payment_request a LEFT JOIN project p ON p.id = a.project_id LEFT JOIN sys_account applicant ON applicant.id = a.applicant_id LEFT JOIN sys_account creator ON creator.id = a.created_by
AND a.status != 0 AND a.project_id = #{params.projectId}
AND p.name LIKE CONCAT('%', #{params.projectName}, '%') AND p.name LIKE '%' || #{params.projectName} || '%'
AND applicant.name LIKE CONCAT('%', #{params.applicantName}, '%') AND applicant.name LIKE '%' || #{params.applicantName} || '%'
AND a.status = #{params.status}
ORDER BY a.created_at DESC, a.id DESC
